import React from 'react';
import { Table } from 'reactstrap';

export type TableHeader = {
    label: string;
    className?: string;
}

export type TableData = {
    render: (props?: Object) => any;
    className?: string;
}

export interface TableConfig {
    renderTableRowKey: (props?: Object) => string;
    renderTableDataKey?: (props?: Object) => any;
    tableHeaders: TableHeader[];
    tableData: TableData[];
    className?: string;
}

type CommonTableProps = {
    config: TableConfig;
    data: any;
}

const CommonTable = ({ config, data }: CommonTableProps): JSX.Element => {
    return <Table className={config.className}>
        <thead>
            <tr>
                {config.tableHeaders &&
                    config.tableHeaders
                        .map(header =>
                            <th key={header.label} className={header.className}>
                                {header.label}
                            </th>
                        )}
            </tr>
        </thead>
        <tbody>
            {data &&
                data
                    .map((row, i) =>
                        <tr key={config.renderTableRowKey(row)}>
                            {config.tableData.map(td => <td className={td.className}>
                                {td.render(row)}
                            </td>)}
                        </tr>
                    )
            }
        </tbody>
    </Table>
}

export default CommonTable;