import React from 'react';
import { toMMSS } from '../utilities/utilities';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faTrophy } from '@fortawesome/free-solid-svg-icons';
import moment from 'moment';
import CommonTable, { TableHeader } from './CommonTable';

export interface ProMatch {
    match_id: number;
    duration: number;
    start_time: number;
    radiant_team_id: number;
    radiant_name: string;
    dire_team_id: number;
    dire_name: string;
    leagueid: number;
    league_name: string;
    series_id: number;
    series_type: number;
    radiant_score: number;
    dire_score: number;
    radiant_win: true;
    radiant: true
}

type ProMatchesTableProps = {
    matches: ProMatch[];
}

const ProMatchesTable = ({ matches }: ProMatchesTableProps) => {
    let colPadding = "py-3";

    const config = {
        renderTableRowKey: ({ match_id }) => match_id,
        tableHeaders: [
            { label: "League" }, { label: "Match Id" }, { label: "Duration" },
            { label: "Radiant", className: "text-success" }, { label: "Dire", className: "text-danger" }, { label: "Finished" }]
        ,
        tableData: [
            {
                render: ({ league_name }) => league_name,
                className: colPadding
            },
            {
                render: ({ match_id }) => match_id,
                className: colPadding
            },
            {
                render: ({ duration }) => toMMSS(duration),
                className: `text-center ${colPadding}`
            },
            {
                render: ({ radiant_win, radiant_name }) => {
                    return <>
                        {radiant_win && <FontAwesomeIcon icon={faTrophy} size="sm" />}
                        <span className="text-success">{radiant_name}</span>
                    </>
                },
                className: colPadding
            },
            {
                render: ({ radiant_win, dire_name }) => {
                    return <>
                        {!radiant_win && <FontAwesomeIcon icon={faTrophy} size="sm" />}
                        <span className="text-danger">{dire_name}</span>
                    </>
                },
                className: colPadding
            },
            {
                render: ({ start_time, duration }) => moment.utc(new Date((start_time + duration) * 1000)).fromNow(),
                className: colPadding
            }
        ],

    }

    return <CommonTable config={config} data={matches} />
}

export default ProMatchesTable;